+	want := []string{"mail", "molecule", "wisp"}
+	if len(types) != len(want) {
+		t.Fatalf("got %d types, want %d", len(types), len(want))
+	}
+	for i, got := range types {
+		if got != want[i] {
+			t.Errorf("types[%d] = %q, want %q", i, got, want[i])
+		}
+	}
+}
